// Validate & normalize each row before sending to Supabase.
// Required fields: name, price. Optional: description, stock, category_slug, image_url, reorder_threshold.
const body = $('Bulk Import Webhook').item.json.body;
const rawProducts = body.products || [];

const valid = [];
const rejected = [];

for (const row of rawProducts) {
  const name  = (row.name || '').toString().trim();
  const price = parseFloat(row.price);

  if (!name) { rejected.push({ row, error: 'Missing product name' }); continue; }
  if (isNaN(price) || price <= 0) { rejected.push({ row, error: 'Invalid or missing price' }); continue; }

  valid.push({
    name,
    description:        (row.description || '').toString().trim(),
    price,
    stock:               Number.isFinite(parseInt(row.stock)) ? parseInt(row.stock) : 0,
    category_slug:      (row.category_slug || '').toString().trim() || null,
    image_url:          (row.image_url || '').toString().trim() || null,
    reorder_threshold:  Number.isFinite(parseInt(row.reorder_threshold)) ? parseInt(row.reorder_threshold) : 5,
  });
}

return {
  job_id:          body.job_id,
  supplier_id:     body.supplier_id,
  valid_products:  valid,
  rejected_rows:   rejected,
  total_submitted: rawProducts.length,
};

const validation = $('Validate & Normalize Rows').item.json;
const rpcResult  = ($json[0] || $json) || {};

const succeeded = rpcResult.succeeded || 0;
const failedFromRpc = rpcResult.failed || 0;
const rejectedAtValidation = validation.rejected_rows.length;

const combinedErrors = [
  ...validation.rejected_rows.map(r => ({ stage: 'validation', ...r })),
  ...((rpcResult.errors || []).map(e => ({ stage: 'insert', ...e }))),
];

return {
  job_id:    validation.job_id,
  status:    'completed',
  rows_total:      validation.total_submitted,
  rows_succeeded:  succeeded,
  rows_failed:     failedFromRpc + rejectedAtValidation,
  error_log: combinedErrors,
};

// No valid rows at all — short-circuit straight to a failed job record.
const validation = $('Validate & Normalize Rows').item.json;
return {
  job_id:    validation.job_id,
  status:    'failed',
  rows_total:     validation.total_submitted,
  rows_succeeded: 0,
  rows_failed:    validation.rejected_rows.length,
  error_log: validation.rejected_rows.map(r => ({ stage: 'validation', ...r })),
};
